import { request } from '../axios';

export async function connectToApp(startUrl: string) {
  try {
    return await request({ method: 'GET', url: startUrl });
  } catch (error) {
    const errorMsg = `${(error as Error).message}`;
    const msg = `Could not connect to application at '${startUrl}' [${errorMsg}]`;
    throw new Error(msg);
  }
}
